sql:
SELECT description
FROM evaluation_runs
WHERE evaluation_method = 'manual';

SELECT COUNT(*) AS completed_runs
FROM run_status
WHERE status = 'completed';

SELECT topic, COUNT(*) AS num_runs
FROM evaluation_runs
GROUP BY topic;

SELECT runid, created_at, updated_at, description
FROM evaluation_runs
LIMIT 10;

SELECT runid, COUNT(error_id) AS NumberOfErrors
FROM error_logs
GROUP BY runid;

SELECT er.runid, rs.status, rs.status_message
FROM evaluation_runs er
JOIN run_status rs ON er.runid = rs.runid;

external_knowledge:
- 'Vanguards of data' refers to data scientists;
- 'Wield the automated evaluation wand' signifies using automated methods for evaluations;
- 'Tales they've woven' metaphorically represents the descriptions of their evaluation runs;
- 'Beacon of their success' is a metaphor for the ERR-IA scores, which are a measure of quality in information retrieval;
- 'Latest chapters of their quest' symbolizes the most recent evaluation runs, with the results ordered by the most recently created ones.

